 63→    private func scanFolder() -> [ImageItem] {
 64→        let fm = FileManager.default
 65→        guard let contents = try? fm.contentsOfDirectory(
 66→            at: folderURL,
 67→            includingPropertiesForKeys: [.contentTypeKey],
 68→            options: .skipsHiddenFiles
 69→        ) else { return [] }
 70→
 71→        // Single pass: filter supported files and capture their UTType
 72→        let supported: [(url: URL, type: UTType)] = contents.compactMap { url in
 73→            guard let type = try? url.resourceValues(forKeys: [.contentTypeKey]).contentType,
 74→                  Self.supportedTypes.contains(where: { type.conforms(to: $0) })
 75→            else { return nil }
 76→            return (url, type)
 77→        }
 78→        .sorted { $0.url.lastPathComponent.localizedStandardCompare($1.url.lastPathComponent) == .orderedAscending }
 79→
 80→        // Expand PDFs into per-page items
 81→        return supported.flatMap { (url, type) -> [ImageItem] in
 82→            if type.conforms(to: .pdf) {
 83→                let count = Self.pdfPageCount(for: url)
 84→                guard count > 0 else { return [] }
 85→                return (0..<count).map { ImageItem(url: url, pdfPageIndex: $0) }
