@objc private func gridFrameDidChange(_ note: Notification) {
    let width = availableLayoutWidth
    guard width != lastLayoutWidth else {
        NSLog("[GridResize] SKIPPED width=%.0f==lastLayoutWidth", width)
        return
    }

    // Capture anchor: find item closest to viewport center using current (pre-relayout) attributes.
    // Cannot use cachedVisibleCenter — it reflects the PREVIOUS scroll position,
    // but NSScrollView may have already adjusted clip bounds during resize.
    let clipBounds = gridScrollView.contentView.bounds
    let viewportCenterY = clipBounds.midY
    let beforeScrollY = clipBounds.origin.y
    var anchorIP: IndexPath?
    var oldFraction: CGFloat = 0.5
    let visibleIPs = collectionView.indexPathsForVisibleItems()
    NSLog("[GridResize] ENTER width=%.0f→%.0f visibleIPs=%d scrollY=%.1f viewportCenterY=%.1f", lastLayoutWidth, width, visibleIPs.count, beforeScrollY, viewportCenterY)
    if !visibleIPs.isEmpty {
        var bestIP: IndexPath?
        var bestDist: CGFloat = .greatestFiniteMagnitude
        for ip in visibleIPs {
            if let attrs = collectionView.layoutAttributesForItem(at: ip) {
                let dist = abs(attrs.frame.midY - viewportCenterY)
                if dist < bestDist {
                    bestDist = dist
                    bestIP = ip
                }
            }
        }
        anchorIP = bestIP
        if let ip = bestIP, let attrs = collectionView.layoutAttributesForItem(at: ip) {
            let rawFraction = (viewportCenterY - attrs.frame.minY) / attrs.frame.height
            oldFraction = max(0, min(1, rawFraction))
            NSLog("[GridResize] ANCHOR item=%d frame=%@ fraction=%.3f", ip.item, NSStringFromRect(attrs.frame), oldFraction)
        }
    } else {
        NSLog("[GridResize] WARNING: visibleIPs is EMPTY!")
    }

    updateSpaceAroundLayout()
    collectionView.collectionViewLayout?.invalidateLayout()
    updateScrollerVisibility()

    let afterInvalidateY = gridScrollView.contentView.bounds.origin.y
    NSLog("[GridResize] AFTER invalidate+scroller: scrollY=%.1f (was %.1f)", afterInvalidateY, beforeScrollY)

    // Restore: place anchor item at the same fractional position in viewport
    if let anchorIP {
        collectionView.layoutSubtreeIfNeeded()
        let afterLayoutY = gridScrollView.contentView.bounds.origin.y
        if let attrs = collectionView.layoutAttributesForItem(at: anchorIP) {
            let newAnchorY = attrs.frame.minY + oldFraction * attrs.frame.height
            let clipHeight = gridScrollView.contentView.bounds.height
            let targetOriginY = newAnchorY - clipHeight / 2
            let docHeight = collectionView.frame.height
            let maxOriginY = max(0, docHeight - clipHeight)
            let clampedY = min(max(0, targetOriginY), maxOriginY)
            NSLog("[GridResize] RESTORE afterLayoutY=%.1f → target=%.1f clamped=%.1f (item=%d newFrame=%@ docH=%.0f clipH=%.0f)", afterLayoutY, targetOriginY, clampedY, anchorIP.item, NSStringFromRect(attrs.frame), docHeight, clipHeight)
            gridScrollView.contentView.scroll(to: NSPoint(x: 0, y: clampedY))
            gridScrollView.reflectScrolledClipView(gridScrollView.contentView)
            let finalY = gridScrollView.contentView.bounds.origin.y
            NSLog("[GridResize] FINAL scrollY=%.1f", finalY)
        } else {
            NSLog("[GridResize] RESTORE FAILED: no attrs for item %d afterLayoutY=%.1f", anchorIP.item, afterLayoutY)
        }
    } else {
        NSLog("[GridResize] NO ANCHOR — scroll not restored")
    }
}

