@objc private func gridFrameDidChange(_ note: Notification) {
    let width = availableLayoutWidth
    guard width != lastLayoutWidth else { return }

    // Capture scroll position as fraction of document height.
    // Cannot track a specific item — when column count changes, items move
    // to completely different rows, causing cascading scroll drift to top.
    let clipBounds = gridScrollView.contentView.bounds
    let oldDocHeight = collectionView.frame.height
    let oldScrollFraction: CGFloat
    if oldDocHeight > clipBounds.height {
        oldScrollFraction = clipBounds.origin.y / (oldDocHeight - clipBounds.height)
    } else {
        oldScrollFraction = 0
    }

    updateSpaceAroundLayout()
    collectionView.collectionViewLayout?.invalidateLayout()
    updateScrollerVisibility()

    // Restore: apply same fractional scroll position to new document height
    collectionView.layoutSubtreeIfNeeded()
    let newDocHeight = collectionView.frame.height
    let clipHeight = gridScrollView.contentView.bounds.height
    if newDocHeight > clipHeight {
        let maxOriginY = newDocHeight - clipHeight
        let targetY = oldScrollFraction * maxOriginY
        gridScrollView.contentView.scroll(to: NSPoint(x: 0, y: targetY))
        gridScrollView.reflectScrolledClipView(gridScrollView.contentView)
    }
}

