@objc private func gridFrameDidChange(_ note: Notification) {
    let width = availableLayoutWidth
    guard width != lastLayoutWidth else { return }

    // Capture a fixed baseline on the FIRST frame of a resize session.
    // Reuse it for all subsequent frames to prevent cascading drift caused by
    // wantsVerticalScroller.didSet calling reflectScrolledClipView mid-chain.
    if resizeBaselineCenterFraction == nil {
        let clipBounds = gridScrollView.contentView.bounds
        let docHeight = collectionView.frame.height
        if docHeight > 0 {
            resizeBaselineCenterFraction = (clipBounds.origin.y + clipBounds.height / 2) / docHeight
        } else {
            resizeBaselineCenterFraction = 0
        }
    }
    let centerFraction = resizeBaselineCenterFraction ?? 0

    // Suppress reflectScrolledClipView in wantsVerticalScroller.didSet
    // to prevent it from corrupting scroll position before we restore.
    gridScrollView.suppressScrollerReflect = true

    updateSpaceAroundLayout()
    collectionView.collectionViewLayout?.invalidateLayout()
    updateScrollerVisibility()

    gridScrollView.suppressScrollerReflect = false

    // Restore: place viewport center at same fractional position in new document
    collectionView.layoutSubtreeIfNeeded()
    let newDocHeight = collectionView.frame.height
    let clipHeight = gridScrollView.contentView.bounds.height
    if newDocHeight > clipHeight {
        let targetCenterY = centerFraction * newDocHeight
        let targetOriginY = targetCenterY - clipHeight / 2
        let maxOriginY = newDocHeight - clipHeight
        let clampedY = min(max(0, targetOriginY), maxOriginY)
        gridScrollView.contentView.scroll(to: NSPoint(x: 0, y: clampedY))
        gridScrollView.reflectScrolledClipView(gridScrollView.contentView)
    }

    // Reset baseline after resize settles (no new frame change for 0.15s)
    resizeEndTimer?.invalidate()
    resizeEndTimer = Timer.scheduledTimer(withTimeInterval: 0.15, repeats: false) { [weak self] _ in
        self?.resizeBaselineCenterFraction = nil
    }
}

